import { redirect, type LayoutServerLoad } from './$types';
import { getMyMembership } from '$lib/remote/org.remote';
import { getOrganization } from '$lib/remote/org.remote';

export const load: LayoutServerLoad = async ({ params, cookies }) => {
  // Fetch org by slug
  const orgResult = await getOrganization(params.slug);
  if (!orgResult?.data) {
    throw redirect(307, `/${params.slug}`);
  }

  // Fetch membership role
  const membership = await getMyMembership(orgResult.data.id);

  // Gate: Non-creators redirected to org home
  if (!membership?.role || membership.role === 'member') {
    throw redirect(307, `/${params.slug}?error=access_denied`);
  }

  return {
    org: orgResult.data,
    role: membership.role,
  };
};
