## +page.server.ts Pattern
```typescript
import { error } from '@sveltejs/kit';
import { CACHE_HEADERS } from '$lib/server/cache';
import { getContentBySlug } from '$lib/remote/content.remote';
import { getStreamingUrl, getPlaybackProgress } from '$lib/remote/library.remote';

export const load = async ({ params, locals, setHeaders }) => {
  setHeaders(CACHE_HEADERS.PRIVATE);  // Vary by auth state
  const { slug: orgSlug, contentSlug } = params;

  const result = await getContentBySlug({ orgSlug, contentSlug });
  if (!result?.data) error(404, 'Content not found');
  const content = result.data;

  let hasAccess = false;
  let streamingUrl: string | null = null;
  let progress = { positionSeconds: 0, durationSeconds: 0, completed: false, updatedAt: null };

  if (locals.user) {
    try {
      const streamResult = await getStreamingUrl(content.id);
      streamingUrl = streamResult?.url ?? null;
      hasAccess = !!streamingUrl;
    } catch { hasAccess = false; }

    if (hasAccess) {
      progress = await getPlaybackProgress(content.id);
    }
  }

  return { content, hasAccess, streamingUrl, progress };
};
```

