## Overview
Implement template CRUD and preview endpoints in the notifications-api worker.

## Files to Create/Modify

### 1. Template Routes
File: `workers/notifications-api/src/routes/templates.ts`

```typescript
import { Hono } from 'hono';
import { procedure, createServiceRegistry } from '@codex/worker-utils';
import { createDbClient, schema } from '@codex/database';
import { eq, and, desc } from 'drizzle-orm';
import {
  createGlobalTemplateSchema,
  createOrgTemplateSchema,
  createCreatorTemplateSchema,
  updateTemplateSchema,
  listTemplatesQuerySchema,
  uuidSchema,
} from '@codex/validation';
import type { HonoEnv } from '@codex/shared-types';

const app = new Hono<HonoEnv>();

// ============================================
// GLOBAL TEMPLATES (Platform Owner Only)
// ============================================

// List global templates
app.get('/global', procedure({
  policy: { auth: 'required', roles: ['platform_owner'] },
  input: { query: listTemplatesQuerySchema },
  handler: async (ctx) => {
    const db = createDbClient(ctx.env);
    const { page, limit, status } = ctx.input.query;
    const offset = (page - 1) * limit;

    const where = and(
      eq(schema.emailTemplates.scope, 'global'),
      status ? eq(schema.emailTemplates.status, status) : undefined
    );

    const templates = await db.query.emailTemplates.findMany({
      where,
      limit,
      offset,
      orderBy: [desc(schema.emailTemplates.createdAt)],
    });

    return { data: templates };
  },
}));

// Create global template
app.post('/global', procedure({
  policy: { auth: 'required', roles: ['platform_owner'] },
  input: { body: createGlobalTemplateSchema },
  successStatus: 201,
  handler: async (ctx) => {
    const db = createDbClient(ctx.env);

    const [template] = await db.insert(schema.emailTemplates).values({
      ...ctx.input.body,
      scope: 'global',
      organizationId: null,
      creatorId: null,
      createdBy: ctx.user.id,
    }).returning();

    return { data: template };
  },
}));

// Get global template by ID
app.get('/global/:id', procedure({
  policy: { auth: 'required', roles: ['platform_owner'] },
  input: { params: { id: uuidSchema } },
  handler: async (ctx) => {
    const db = createDbClient(ctx.env);

    const template = await db.query.emailTemplates.findFirst({
      where: and(
        eq(schema.emailTemplates.id, ctx.input.params.id),
        eq(schema.emailTemplates.scope, 'global')
      ),
    });

    if (!template) {
      return ctx.json({ error: 'Template not found' }, 404);
    }

    return { data: template };
  },
}));

// Update global template
app.patch('/global/:id', procedure({
  policy: { auth: 'required', roles: ['platform_owner'] },
  input: { params: { id: uuidSchema }, body: updateTemplateSchema },
  handler: async (ctx) => {
    const db = createDbClient(ctx.env);

    const [template] = await db.update(schema.emailTemplates)
      .set(ctx.input.body)
      .where(and(
        eq(schema.emailTemplates.id, ctx.input.params.id),
        eq(schema.emailTemplates.scope, 'global')
      ))
      .returning();

    if (!template) {
      return ctx.json({ error: 'Template not found' }, 404);
    }

    return { data: template };
  },
}));

// Delete global template (soft delete)
app.delete('/global/:id', procedure({
  policy: { auth: 'required', roles: ['platform_owner'] },
  input: { params: { id: uuidSchema } },
  handler: async (ctx) => {
    const db = createDbClient(ctx.env);

    const [template] = await db.update(schema.emailTemplates)
      .set({ deletedAt: new Date() })
      .where(and(
        eq(schema.emailTemplates.id, ctx.input.params.id),
        eq(schema.emailTemplates.scope, 'global')
      ))
      .returning();

    if (!template) {
      return ctx.json({ error: 'Template not found' }, 404);
    }

    return { data: { deleted: true } };
  },
}));

// ============================================
// ORGANIZATION TEMPLATES
// ============================================

// List org templates
app.get('/organizations/:organizationId/templates', procedure({
  policy: { auth: 'required' },
  input: { 
    params: { organizationId: uuidSchema },
    query: listTemplatesQuerySchema 
  },
  handler: async (ctx) => {
    const db = createDbClient(ctx.env);
    const { organizationId } = ctx.input.params;
    const { page, limit, status } = ctx.input.query;
    const offset = (page - 1) * limit;

    // Check org membership
    const membership = await db.query.organizationMemberships.findFirst({
      where: and(
        eq(schema.organizationMemberships.userId, ctx.user.id),
        eq(schema.organizationMemberships.organizationId, organizationId),
        eq(schema.organizationMemberships.status, 'active')
      ),
    });

    if (!membership) {
      return ctx.json({ error: 'Not a member of this organization' }, 403);
    }

    const where = and(
      eq(schema.emailTemplates.scope, 'organization'),
      eq(schema.emailTemplates.organizationId, organizationId),
      status ? eq(schema.emailTemplates.status, status) : undefined
    );

    const templates = await db.query.emailTemplates.findMany({
      where,
      limit,
      offset,
      orderBy: [desc(schema.emailTemplates.createdAt)],
    });

    return { data: templates };
  },
}));

// Create org template
app.post('/organizations/:organizationId/templates', procedure({
  policy: { auth: 'required', roles: ['admin', 'owner'] },
  input: { 
    params: { organizationId: uuidSchema },
    body: createOrgTemplateSchema 
  },
  successStatus: 201,
  handler: async (ctx) => {
    const db = createDbClient(ctx.env);
    const { organizationId } = ctx.input.params;

    // Verify admin/owner membership
    const membership = await db.query.organizationMemberships.findFirst({
      where: and(
        eq(schema.organizationMemberships.userId, ctx.user.id),
        eq(schema.organizationMemberships.organizationId, organizationId),
        eq(schema.organizationMemberships.status, 'active')
      ),
    });

    if (!membership || !['admin', 'owner'].includes(membership.role)) {
      return ctx.json({ error: 'Admin access required' }, 403);
    }

    const [template] = await db.insert(schema.emailTemplates).values({
      ...ctx.input.body,
      scope: 'organization',
      organizationId,
      creatorId: null,
      createdBy: ctx.user.id,
    }).returning();

    return { data: template };
  },
}));

