  if (err instanceof Stripe.errors.StripeConnectionError || err instanceof Stripe.errors.StripeAPIError) {
    throw err; // transient — let Stripe retry the webhook
  }
  // permanent — record as pending payout
  await this.recordPendingPayout(...);
}
