      .from({ item: libraryCollection })
      .where(({ item }) =>
        showCompleted ? true : eq(item.progress?.completed, false)
      )
      .orderBy(({ item }) => item.progress?.updatedAt ?? item.purchasedAt, 'desc'),
    [() => showCompleted]
  );
</script>

<label>
  <input type="checkbox" bind:checked={showCompleted} />
  Show completed
</label>

{#if library.isLoading}
  <LibrarySkeleton />
{:else}
  <ul>
    {#each library.data as item (item.content.id)}
      <li>
        <a href="/watch/{item.content.id}">
          <img src={item.content.thumbnailUrl} alt="" />
          <span>{item.content.title}</span>
        </a>

        {#if item.progress}
          <progress 
            value={item.progress.positionSeconds} 
            max={item.progress.durationSeconds}
          />
          <span>{formatProgress(item.progress)}</span>
        {/if}
      </li>
    {/each}
  </ul>
{/if}
```

### Video Player with Optimistic Progress
```svelte
<script>
  import { updateProgress } from '$lib/collections/library';

  let { data } = $props();
  let videoEl: HTMLVideoElement;
  let saveTimer: number;

  // Debounced progress save (every 5 seconds)
  function handleTimeUpdate() {
    clearTimeout(saveTimer);
    saveTimer = setTimeout(() => {
      updateProgress(
        data.content.id,
        videoEl.currentTime,
        videoEl.duration
      );
      // UI updates IMMEDIATELY (optimistic)
      // Server sync happens in background via onUpdate
    }, 5000);
  }

  // Save on pause/close
  function handlePause() {
    clearTimeout(saveTimer);
    updateProgress(
      data.content.id,
      videoEl.currentTime,
      videoEl.duration
    );
  }
</script>

<video
  bind:this={videoEl}
  src={data.streamingUrl}
  ontimeupdate={handleTimeUpdate}
  onpause={handlePause}
/>
```

## Key Concepts

### Optimistic Updates Flow
```
User action (seek video)
       │
       ▼
collection.update()
       │
       ├──► UI updates IMMEDIATELY (optimistic)
       │
       ▼
onUpdate handler called
       │
       ├──► savePlaybackProgress() to server
       │
       ├─── Success: done
       │
       └─── Failure: AUTOMATIC ROLLBACK
                     UI reverts to previous state
```

### Draft Updates (Immer-style)
```typescript
libraryCollection.update(contentId, (draft) => {
  // Mutate draft directly - TanStack DB handles immutability
  draft.progress.positionSeconds = 120;
  draft.progress.completed = true;
});
```

### Error Handling
- If `onUpdate` throws, transaction rolls back automatically
- UI reverts to previous state
- Error can be caught for user notification

## Verification

1. Library loads user's content
2. Progress bar reflects saved progress
3. Video seek updates progress optimistically (instant)
4. Progress persists after page refresh
5. Failed save rolls back UI state

## References

- [TanStack DB: Optimistic Mutations](https://tanstack.com/db/latest/docs/guides/mutations)
- [TanStack DB: Error Handling](https://tanstack.com/db/latest/docs/guides/error-handling)

