```typescript
import { error } from '@sveltejs/kit';
import { createServerApi } from '$lib/server/api';
import type { PageServerLoad } from './$types';

export const load: PageServerLoad = async ({ params, platform, cookies }) => {
  const api = createServerApi(platform, cookies);

  // Fetch creator profile by username
  const creator = await api.fetch('content', `/api/creators/${params.username}`);

  if (!creator) {
    error(404, { message: 'Creator not found' });
  }

  // Fetch creator's latest published content (limit 6 for initial view)
  const content = await api.content.list(
    new URLSearchParams({
      creatorUsername: params.username,
      status: 'published',
      limit: '6',
      sort: 'newest'
    })
  );

  return {
    creator: creator.data,
    content: content.data ?? [],
    contentTotal: content.pagination?.totalCount ?? 0,
    username: params.username
  };
};
```

