# Phase 3.2: Content Collection

Create the TanStack DB collection for content data with live queries.

## Files to Create

### `apps/web/src/lib/collections/content.ts`

```typescript
import { createCollection } from '@tanstack/svelte-db';
import { queryCollectionOptions } from '@tanstack/query-db-collection';
import { listContent, getContent } from '$lib/remote/content.remote';
import { queryClient } from './index';
import type { ContentWithRelations } from '$lib/types';

/**
 * Content Collection
 * 
 * Local-first store for content data.
 * Powered by listContent() remote function.
 * Enables sub-ms client-side queries and joins.
 */
export const contentCollection = createCollection(
  queryCollectionOptions<ContentWithRelations>({
    id: 'content',
    queryKey: ['content'],

    // Load data via remote function
    queryFn: async () => {
      const result = await listContent({ status: 'published' });
      return result.items;
    },

    queryClient,
    getKey: (item) => item.id,

    // Optional: sync mode for large datasets
    // syncMode: 'on-demand',  // Only fetch when queried
  })
);

/**
 * For on-demand loading with filters
 * Use when you need server-side filtering
 */
export async function loadContentForOrg(organizationId: string) {
  const result = await listContent({ organizationId, status: 'published' });
  // Manually populate collection if needed
  // contentCollection.setState(result.items);
  return result.items;
}
```

## Usage Examples

### Basic Live Query
```svelte
<script>
  import { useLiveQuery, contentCollection, eq } from '$lib/collections';

  // Sub-ms query, reactive to collection changes
  const publishedContent = useLiveQuery((q) =>
    q.from({ content: contentCollection })
     .where(({ content }) => eq(content.status, 'published'))
     .orderBy(({ content }) => content.createdAt, 'desc')
  );
</script>

{#if publishedContent.isLoading}
  <p>Loading...</p>
{:else}
  {#each publishedContent.data as item (item.id)}
    <ContentCard {item} />
  {/each}
{/if}
```

### With Reactive Filters
```svelte
<script>
  import { useLiveQuery, contentCollection, eq } from '$lib/collections';

  let searchTerm = $state('');
  let selectedType = $state('all');

  // Query re-runs when dependencies change
  const filteredContent = useLiveQuery(
    (q) => {
      let query = q.from({ content: contentCollection });

      if (selectedType !== 'all') {
        query = query.where(({ content }) => 
          eq(content.mediaType, selectedType)
        );
      }

      return query;
    },
    [() => selectedType]  // Reactive deps
  );

  // Client-side search (instant, no server call)
  const results = $derived(
    filteredContent.data?.filter(item =>
      item.title.toLowerCase().includes(searchTerm.toLowerCase())
    ) ?? []
  );
</script>

<input type="search" bind:value={searchTerm} />
<select bind:value={selectedType}>
  <option value="all">All</option>
  <option value="video">Video</option>
  <option value="audio">Audio</option>
</select>

{#each results as item (item.id)}
  <ContentCard {item} />
{/each}
```

### Join with Organization
```svelte
<script>
  import { useLiveQuery, contentCollection, orgCollection, eq } from '$lib/collections';

  // Client-side join (sub-ms)
  const contentWithOrg = useLiveQuery((q) =>
    q.from({ content: contentCollection })
     .join(
       { org: orgCollection },
       ({ content, org }) => eq(content.organizationId, org.id),
       'inner'
     )
     .select(({ content, org }) => ({
       id: content.id,
       title: content.title,
       orgName: org.name,
       orgLogo: org.logoUrl,
     }))
  );
</script>
```

## Key Concepts

### Why Collections over Direct Queries?
1. **Sub-ms local queries** - No network latency for filtering/sorting
2. **Reactive updates** - UI updates automatically when data changes
3. **Joins** - Combine data from multiple collections client-side
4. **Optimistic updates** - Instant UI feedback

### queryFn vs Direct Fetch
The `queryFn` wraps the remote function, which wraps the server API.
This layered approach gives us:
- Type safety from remote function schemas
- Caching from QueryClient
- Local querying from TanStack DB

