export const getPublicBranding = query(z.string(), async (slug) => {
  const { platform } = getRequestEvent();
  const orgApiUrl = serverApiUrl(platform, 'org');

  const res = await fetch(`${orgApiUrl}/api/organizations/public/${slug}`);
  if (!res.ok) return null;
  return res.json();
});

// Get organization settings (authenticated, for admin)
export const getOrgSettings = query(z.string().uuid(), async (orgId) => {
  const { platform, cookies } = getRequestEvent();
  const api = createServerApi(platform, cookies);
  return api.org.getSettings(orgId);
});
