#### +page.server.ts

import { fail } from '@sveltejs/kit';
import { createServerApi } from '$lib/server/api';
import { logger } from '$lib/observability';
import type { Actions, PageServerLoad } from './$types';

interface NotificationPreferences {
  emailMarketing: boolean;
  emailPurchaseReceipts: boolean;
  emailContentUpdates: boolean;
  emailSecurityAlerts: boolean;
}

export const load: PageServerLoad = async ({ parent, cookies, platform }) => {
  const { user } = await parent();

  // Load current notification preferences
  // Endpoint TBD — likely GET /api/notifications/preferences or GET /api/users/me/preferences
  try {
    const api = createServerApi(platform, cookies);
    const prefs = await api.fetch<{ data: NotificationPreferences }>(
      'notifications', '/api/notifications/preferences'
    );
    return { user, preferences: prefs.data };
  } catch {
    // Default preferences if endpoint unavailable
    return {
      user,
      preferences: {
        emailMarketing: true,
        emailPurchaseReceipts: true,
        emailContentUpdates: true,
        emailSecurityAlerts: true,
      },
    };
  }
};

export const actions: Actions = {
  updatePreferences: async ({ request, cookies, platform }) => {
    const data = await request.formData();

    const preferences: NotificationPreferences = {
      emailMarketing: data.get('emailMarketing') === 'on',
      emailPurchaseReceipts: data.get('emailPurchaseReceipts') === 'on',
      emailContentUpdates: data.get('emailContentUpdates') === 'on',
      emailSecurityAlerts: data.get('emailSecurityAlerts') === 'on',
    };

    try {
      const api = createServerApi(platform, cookies);
      await api.fetch('notifications', '/api/notifications/preferences', undefined, {
        method: 'PUT',
        body: JSON.stringify(preferences),
      });
      return { success: true };
    } catch (err) {
      logger.error('Notification preferences update error', {
        error: err instanceof Error ? err.message : String(err),
      });
      return fail(500, { error: 'Failed to save preferences. Please try again.' });
    }
  },
};

